+const sourceSeed = [
+  { id: 's1', type: 'rss', name: 'The Verge', cadence: 'Live', active: true },
+  { id: 's2', type: 'rss', name: 'MIT Technology Review', cadence: 'Hourly', active: true },
+  { id: 's3', type: 'youtube', name: 'MKBHD', cadence: 'New uploads', active: true },
