+  { id: 's6', type: 'newsletter', name: 'Lenny Letter', cadence: 'Weekly', active: false }
+];
+
+const typeMeta = {
+  all: { label: 'All', icon: LayoutGrid },
+  rss: { label: 'RSS', icon: Rss },
+  youtube: { label: 'YouTube', icon: Video },
+  newsletter: { label: 'Newsletters', icon: Mail }
+};
+
+function useStoredState(key, initialValue) {
+  const [value, setValue] = useState(() => {
+    try {
+      const stored = localStorage.getItem(key);
+      return stored ? JSON.parse(stored) : initialValue;
+    } catch {
+      return initialValue;
+    }
+  });
+
+  const setStoredValue = (next) => {
+    setValue((current) => {
+      const resolved = typeof next === 'function' ? next(current) : next;
+      localStorage.setItem(key, JSON.stringify(resolved));
+      return resolved;
+    });
+  };
+
+  return [value, setStoredValue];
+}
+
+function App() {
+  const [items, setItems] = useStoredState('signal-desk-items', initialItems);
+  const [sources, setSources] = useStoredState('signal-desk-sources', sourceSeed);
+  const [activeType, setActiveType] = useState('all');
+  const [query, setQuery] = useState('');
+  const [focus, setFocus] = useState('unread');
+  const [selectedId, setSelectedId] = useState(items[0]?.id);
+  const [newSource, setNewSource] = useState({ type: 'rss', name: '', cadence: 'Daily' });
+
+  const filteredItems = useMemo(() => {
+    return items.filter((item) => {
+      const matchesType = activeType === 'all' || item.type === activeType;
+      const matchesFocus =
+        focus === 'all' ||
+        (focus === 'unread' && item.unread) ||
+        (focus === 'saved' && item.saved) ||
+        (focus === 'priority' && item.priority === 'high');
+      const text = `${item.title} ${item.source} ${item.summary} ${item.topic}`.toLowerCase();
+      return matchesType && matchesFocus && text.includes(query.toLowerCase());
+    });
+  }, [activeType, focus, items, query]);
+
+  const selectedItem = items.find((item) => item.id === selectedId) || filteredItems[0] || items[0];
+  const stats = useMemo(() => {
+    const unread = items.filter((item) => item.unread).length;
+    const saved = items.filter((item) => item.saved).length;
+    const high = items.filter((item) => item.priority === 'high').length;
+    return { unread, saved, high, total: items.length };
+  }, [items]);
+
+  const toggleItem = (id, key) => {
+    setItems((current) => current.map((item) => (item.id === id ? { ...item, [key]: !item[key] } : item)));
+  };
+
+  const markRead = (id) => {
+    setItems((current) => current.map((item) => (item.id === id ? { ...item, unread: false } : item)));
+  };
+
+  const removeItem = (id) => {
+    setItems((current) => current.filter((item) => item.id !== id));
+    if (selectedId === id) setSelectedId(filteredItems.find((item) => item.id !== id)?.id);
+  };
+
+  const addSource = (event) => {
+    event.preventDefault();
+    const trimmed = newSource.name.trim();
+    if (!trimmed) return;
+
+    setSources((current) => [
+      ...current,
+      {
+        id: crypto.randomUUID(),
+        type: newSource.type,
+        name: trimmed,
+        cadence: newSource.cadence,
+        active: true
+      }
+    ]);
+    setNewSource({ type: 'rss', name: '', cadence: 'Daily' });
+  };
+
+  const toggleSource = (id) => {
+    setSources((current) => current.map((source) => (source.id === id ? { ...source, active: !source.active } : source)));
+  };
+
+  return (
+    <main className="app-shell">
+      <aside className="sidebar">
+        <div className="brand">
+          <span className="brand-mark">
+            <Sparkles size={18} />
+          </span>
+          <div>
+            <h1>Signal Desk</h1>
+            <p>Unified reading queue</p>
+          </div>
+        </div>
+
+        <nav className="source-nav" aria-label="Content types">
+          {Object.entries(typeMeta).map(([key, meta]) => {
+            const Icon = meta.icon;
+            const count = key === 'all' ? items.length : items.filter((item) => item.type === key).length;
+            return (
+              <button
+                className={activeType === key ? 'nav-item is-active' : 'nav-item'}
+                key={key}
+                onClick={() => setActiveType(key)}
+                type="button"
+              >
+                <Icon size={18} />
+                <span>{meta.label}</span>
+                <strong>{count}</strong>
+              </button>
+            );
+          })}
+        </nav>
+
+        <section className="sources-panel" aria-label="Connected sources">
+          <div className="panel-heading">
+            <span>Sources</span>
+            <Settings2 size={16} />
+          </div>
+          <div className="source-list">
+            {sources.map((source) => {
+              const Icon = typeMeta[source.type].icon;
+              return (
+                <button
+                  type="button"
+                  className={source.active ? 'source-row' : 'source-row is-muted'}
+                  key={source.id}
+                  onClick={() => toggleSource(source.id)}
+                  title={source.active ? 'Pause source' : 'Resume source'}
+                >
+                  <Icon size={16} />
+                  <span>{source.name}</span>
+                  <small>{source.cadence}</small>
+                </button>
+              );
+            })}
+          </div>
+        </section>
+      </aside>
+
+      <section className="main-panel">
+        <header className="topbar">
+          <div className="search-box">
+            <Search size={18} />
+            <input
+              aria-label="Search saved content"
+              placeholder="Search feeds, channels, newsletters..."
+              value={query}
+              onChange={(event) => setQuery(event.target.value)}
+            />
+          </div>
+          <div className="top-actions">
+            <button type="button" className="icon-button" title="Notifications">
+              <Bell size={18} />
+            </button>
+            <button type="button" className="primary-action">
+              <Plus size={18} />
+              <span>Add connection</span>
+            </button>
+          </div>
+        </header>
+
+        <section className="metrics-grid" aria-label="Dashboard metrics">
+          <Metric icon={Inbox} label="Unread" value={stats.unread} note={`${stats.total} total items`} />
+          <Metric icon={Star} label="Priority" value={stats.high} note="Needs attention" />
+          <Metric icon={Bookmark} label="Saved" value={stats.saved} note="For later" />
+          <Metric icon={Clock3} label="Digest time" value="42m" note="Estimated queue" />
+        </section>
+
+        <div className="workspace-grid">
+          <section className="feed-column" aria-label="Unified inbox">
+            <div className="section-toolbar">
+              <div>
+                <h2>Inbox</h2>
+                <p>{filteredItems.length} matched items</p>
+              </div>
+              <label className="select-control">
+                <span>Focus</span>
+                <select value={focus} onChange={(event) => setFocus(event.target.value)}>
+                  <option value="unread">Unread</option>
+                  <option value="priority">Priority</option>
+                  <option value="saved">Saved</option>
+                  <option value="all">Everything</option>
+                </select>
+                <ChevronDown size={16} />
+              </label>
+            </div>
+
+            <div className="item-list">
+              {filteredItems.map((item) => (
+                <ArticleRow
+                  item={item}
+                  key={item.id}
+                  selected={selectedItem?.id === item.id}
+                  onOpen={() => {
+                    setSelectedId(item.id);
+                    markRead(item.id);
+                  }}
+                  onSave={() => toggleItem(item.id, 'saved')}
+                  onRemove={() => removeItem(item.id)}
+                />
+              ))}
+              {filteredItems.length === 0 && (
+                <div className="empty-state">
+                  <Inbox size={22} />
+                  <p>No items match the current filters.</p>
+                </div>
+              )}
+            </div>
+          </section>
+
+          <aside className="detail-column" aria-label="Selected item and source manager">
+            {selectedItem && (
+              <article className="reader-panel">
+                <div className={`type-pill ${selectedItem.type}`}>
+                  {React.createElement(typeMeta[selectedItem.type].icon, { size: 15 })}
+                  <span>{typeMeta[selectedItem.type].label}</span>
+                </div>
+                <h2>{selectedItem.title}</h2>
+                <p>{selectedItem.summary}</p>
+                <div className="detail-meta">
+                  <span>{selectedItem.source}</span>
+                  <span>{selectedItem.topic}</span>
+                  <span>{selectedItem.readTime}</span>
+                </div>
+                <div className="reader-actions">
+                  <button type="button" onClick={() => toggleItem(selectedItem.id, 'saved')}>
+                    <Bookmark size={17} />
+                    <span>{selectedItem.saved ? 'Saved' : 'Save'}</span>
+                  </button>
+                  <a href={selectedItem.url}>
+                    <ExternalLink size={17} />
+                    <span>Open</span>
+                  </a>
+                </div>
+              </article>
+            )}
+
+            <section className="connector-panel">
+              <div className="section-toolbar compact">
+                <div>
+                  <h2>Add Source</h2>
+                  <p>RSS, channels, and newsletter senders</p>
+                </div>
+              </div>
+              <form className="connector-form" onSubmit={addSource}>
+                <div className="segmented-control" role="group" aria-label="New source type">
+                  {['rss', 'youtube', 'newsletter'].map((type) => {
+                    const Icon = typeMeta[type].icon;
+                    return (
+                      <button
+                        type="button"
+                        className={newSource.type === type ? 'is-selected' : ''}
+                        key={type}
+                        onClick={() => setNewSource((current) => ({ ...current, type }))}
+                        title={typeMeta[type].label}
+                      >
+                        <Icon size={17} />
+                      </button>
+                    );
+                  })}
+                </div>
+                <input
+                  placeholder="Source name or URL"
+                  value={newSource.name}
+                  onChange={(event) => setNewSource((current) => ({ ...current, name: event.target.value }))}
+                />
+                <select
+                  value={newSource.cadence}
+                  onChange={(event) => setNewSource((current) => ({ ...current, cadence: event.target.value }))}
+                >
+                  <option>Live</option>
+                  <option>Hourly</option>
+                  <option>Daily</option>
+                  <option>Weekly</option>
+                  <option>New uploads</option>
+                </select>
+                <button className="submit-button" type="submit">
+                  <Plus size={17} />
+                  <span>Add source</span>
+                </button>
+              </form>
+            </section>
+          </aside>
+        </div>
+      </section>
+    </main>
+  );
+}
+
+function Metric({ icon: Icon, label, value, note }) {
+  return (
+    <div className="metric">
+      <Icon size={18} />
+      <div>
+        <span>{label}</span>
+        <strong>{value}</strong>
+        <small>{note}</small>
+      </div>
+    </div>
+  );
+}
+
+function ArticleRow({ item, selected, onOpen, onSave, onRemove }) {
+  const Icon = typeMeta[item.type].icon;
+
+  return (
+    <article className={selected ? 'article-row is-selected' : 'article-row'}>
+      <button type="button" className="article-body" onClick={onOpen}>
+        <span className={`source-icon ${item.type}`}>
+          <Icon size={17} />
+        </span>
+        <span className="article-copy">
+          <span className="article-meta">
+            <strong>{item.source}</strong>
+            <small>{item.time}</small>
+            {item.unread && <i>Unread</i>}
+          </span>
+          <span className="article-title">{item.title}</span>
+          <span className="article-summary">{item.summary}</span>
+        </span>
+      </button>
+      <div className="row-actions">
+        <button type="button" onClick={onSave} title={item.saved ? 'Remove saved' : 'Save'}>
+          <Bookmark size={16} fill={item.saved ? 'currentColor' : 'none'} />
+        </button>
+        <button type="button" onClick={onRemove} title="Remove">
+          <Trash2 size={16} />
+        </button>
+      </div>
+    </article>
+  );
+}
+
+createRoot(document.getElementById('root')).render(<App />);
