  }
}

@media (max-width: 820px) {
  .app-shell {
    display: block;
  }

  .sidebar {
    height: auto;
    position: static;
  }

  .source-nav {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .topbar {
    grid-template-columns: 1fr;
  }

  .top-actions {
    justify-content: space-between;
  }

  .primary-action {
    flex: 1;
  }

  .main-panel {
    padding: 18px;
  }
}

@media (max-width: 560px) {
  .metrics-grid,
  .source-nav {
    grid-template-columns: 1fr;
  }

  .article-row {
    grid-template-columns: 1fr;
  }

  .row-actions {
    justify-content: flex-end;
    padding: 0 6px 4px;
  }

  .article-body {
    grid-template-columns: 34px minmax(0, 1fr);
  }

  .source-icon {
    height: 34px;
    width: 34px;
  }

  .section-toolbar {
    align-items: stretch;
    flex-direction: column;
    gap: 10px;
  }

  .select-control {
    grid-template-columns: auto minmax(0, 1fr) 16px;
  }

  .reader-panel h2 {
    font-size: 21px;
  }
}

