import React, { useMemo, useState } from 'react';
import { createRoot } from 'react-dom/client';
import {
  Bell,
  Bookmark,
  Check,
  ChevronDown,
  Clock3,
  ExternalLink,
  Inbox,
  LayoutGrid,
  Mail,
  Plus,
  Rss,
  Search,
  Settings2,
  Sparkles,
  Star,
  Trash2,
  Video,
  X
} from 'lucide-react';
import './styles.css';

const initialItems = [
  {
    id: 1,
    type: 'rss',
    source: 'The Verge',
    title: 'A practical look at personal AI devices after the hype cycle',
    summary:
      'Field notes on battery life, privacy indicators, and why companion apps still carry most of the experience.',
