    unread: true,
    saved: true,
    priority: 'medium'
  },
  {
    id: 3,
    type: 'newsletter',
    source: 'Morning Brew',
    title: 'Markets open higher as chipmakers lead early trading',
    summary:
      'The brief covers premarket movement, retail earnings, and three policy decisions expected later this week.',
    topic: 'Business',
    time: '44 min ago',
    readTime: '6 min',
    url: '#',
    unread: true,
    saved: false,
    priority: 'high'
  },
  {
    id: 4,
    type: 'rss',
    source: 'Nielsen Norman Group',
    title: 'Why dense dashboards still need visible hierarchy',
    summary:
      'Research-backed guidance for reducing scanning cost without hiding essential operational details.',
    topic: 'Design',
    time: '1 hr ago',
    readTime: '8 min',
    url: '#',
    unread: false,
